allow:
Bash(powershell.exe -Command "
\\$procs = Get-NetTCPConnection -LocalPort 8000 -ErrorAction SilentlyContinue
foreach \(\\$p in \\$procs\) {
    Write-Host 'Killing PID' \\$p.OwningProcess
    Stop-Process -Id \\$p.OwningProcess -Force -ErrorAction SilentlyContinue
}
Start-Sleep -Seconds 2
\\$check = Get-NetTCPConnection -LocalPort 8000 -ErrorAction SilentlyContinue
if \(\\$check\) { Write-Host 'Still running on 8000!' } else { Write-Host 'Port 8000 is free' }
")
